function ic_apply_range_slider(i){if("function"==typeof i.ionRangeSlider){var e=1,a=i.data("unit"),n=i.data("min"),t=i.data("max"),o=i.data("current-min"),r=i.data("current-max");t-n<2&&(e=.1),o===r&&(o===n?r+=e:o-=e),i.ionRangeSlider({type:"double",min:n,max:t,from:o,to:r,step:e,postfix:" "+a,grid:!0,hide_min_max:!0,onFinish:function(){i.closest("form").submit(),i.closest(".product_size_filter").addClass("active")}})}}jQuery(document).ready(function(i){i("body").on("reload",".ic-slider-container",function(){var e=i(this);e.removeClass("toReload"),e.find(".ic-range-slider").each(function(){ic_apply_range_slider(i(this))})}),i(".ic-slider-container.toReload").trigger("reload")});